query:
DELETE FROM lessons WHERE id NOT IN (
  SELECT id FROM (
    SELECT l.id FROM lessons l
    JOIN courses c ON l.courseId = c.id
    WHERE l.id IN (
      SELECT id FROM (
        SELECT l2.id, ROW_NUMBER() OVER (PARTITION BY l2.courseId ORDER BY l2.lessonOrder) as rn,
               CASE WHEN c2.code = 'DIV111' THEN 8 ELSE 10 END as target
        FROM lessons l2
        JOIN courses c2 ON l2.courseId = c2.id
      ) ranked
      WHERE rn <= target
    )
  ) keep_ids
);

